import{u as r}from"./api.BhIwWj_B.js";import"./auth.h-v8t-lg.js";import"./hoisted.jgWgEjQ_.js";document.querySelectorAll(".toggle-role-btn").forEach(t=>{t.addEventListener("click",async()=>{const e=t.getAttribute("data-id"),o=t.getAttribute("data-role")==="admin"?"user":"admin";try{await r.updateRole(e,o),window.location.reload()}catch{alert("Error al actualizar rol")}})});document.querySelectorAll(".toggle-active-btn").forEach(t=>{t.addEventListener("click",async()=>{const e=t.getAttribute("data-id");try{await r.toggleActive(e),window.location.reload()}catch{alert("Error al cambiar estado")}})});
